    setFormRep({observacion:"",huboIncidente:"Sin incidente",foto:null,area:AREAS_EDIFICIO[0],urgencia:"Normal",areaOtro:"",turno:"☀️ Tarde",descripcionIncidente:""});
    setNovedadesHora([]);setNuevaNovedad({hora:"",texto:""});
